 28	  shouldHidePipelineRunStopForTaskRunStatus,
 29	} from '../utils/pipeline-augment';
 30	import {
 31	  isResourceLoadedFromTR,
 32	  tektonResultsFlag,
 33	} from '../utils/common-utils';
 34	import { errorModal } from '../modals/error-modal';
 35	
 36	type PipelineRunsKebabProps = {
 37	  obj: PipelineRunKind;
 38	  taskRuns: TaskRunKind[];
 39	  taskRunStatusObj: TaskStatus;
 40	  currentUser: string;
 41	};
 42	
 43	const PipelineRunsKebab: React.FC<PipelineRunsKebabProps> = ({
 44	  obj,
 45	  taskRuns,
 46	  taskRunStatusObj,
 47	  currentUser,
 48	}) => {
 49	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 50	  const message = (
 51	    <p>
 52	      {t(
 53	        'This action will delete resource from k8s but still the resource can be fetched from Tekton Results',
 54	      )}
 55	    </p>
 56	  );
 57	
 58	  const launchDeleteModal =
 59	    !isResourceLoadedFromTR(obj) && tektonResultsFlag(obj)
 60	      ? useDeleteModal(obj, undefined, message)
 61	      : useDeleteModal(obj);
 62	  const [isOpen, setIsOpen] = React.useState(false);
 63	  const { name, namespace } = obj.metadata;
 64	  const PLRTasks = getTaskRunsOfPipelineRun(taskRuns, name);
 65	  const hidePLRCancel = taskRunStatusObj
 66	    ? shouldHidePipelineRunCancelForTaskRunStatus(obj, taskRunStatusObj)
 67	    : shouldHidePipelineRunCancel(obj, PLRTasks);
 68	  const hidePLRStop = taskRunStatusObj
 69	    ? shouldHidePipelineRunStopForTaskRunStatus(obj, taskRunStatusObj)
 70	    : shouldHidePipelineRunStop(obj, PLRTasks);
 71	  const onToggle = () => {
 72	    setIsOpen(!isOpen);
 73	  };
 74	
 75	  const onSelect = () => {
 76	    setIsOpen(false);
 77	  };
 78	
 79	  const canCreateResource = useAccessReview({
 80	    group: PipelineRunModel.apiGroup,
 81	    resource: PipelineRunModel.plural,
 82	    verb: 'create',
 83	    name,
 84	    namespace,
 85	  });
 86	
 87	  const canEditResource = useAccessReview({
 88	    group: PipelineRunModel.apiGroup,
 89	    resource: PipelineRunModel.plural,
 90	    verb: 'update',
 91	    name,
 92	    namespace,
 93	  });
 94	  const canDeleteResource = useAccessReview({
 95	    group: PipelineRunModel.apiGroup,
 96	    resource: PipelineRunModel.plural,
 97	    verb: 'delete',
 98	    name,
 99	    namespace,
100	  });
101	
102	  const reRunAction = () => {
103	    const { pipelineRef, pipelineSpec } = obj.spec;
104	    if (
105	      namespace &&
106	      (pipelineRef?.name || pipelineSpec || pipelineRef?.resolver)
107	    ) {
108	      k8sCreate({
109	        model: returnValidPipelineRunModel(obj),
110	        data: getPipelineRunData(null, currentUser, obj),
111	      });
112	    } else {
113	      errorModal({
114	        error: t(
115	          'Invalid PipelineRun configuration, unable to start Pipeline.',
116	        ),
117	      });
118	    }
119	  };
120	
121	  const cancelAction = () => {
122	    k8sPatch({
123	      model: PipelineRunModel,
124	      resource: {
125	        metadata: {
126	          name,
127	          namespace,
128	        },
129	      },
130	      data: [
131	        {
132	          op: 'replace',
133	          path: `/spec/status`,
134	          value: 'CancelledRunFinally',
135	        },
136	      ],
137	    });
138	  };
139	
140	  const stopAction = () => {
141	    k8sPatch({
142	      model: PipelineRunModel,
143	      resource: {
144	        metadata: { name, namespace },
145	      },
146	      data: [
147	        {
148	          op: 'replace',
149	          path: `/spec/status`,
150	          value: 'StoppedRunFinally',
151	        },
152	      ],
153	    });
154	  };
155	
156	  const dropdownItems = [
157	    <DropdownItem
158	      key="reRun"
159	      component="button"
160	      isDisabled={!canCreateResource}
161	      data-test-action="reRun-pipelineRun"
162	      onClick={reRunAction}
163	    >
164	      {t('Rerun')}
165	    </DropdownItem>,
166	
167	    ...(!hidePLRCancel
168	      ? [
169	          <DropdownItem
170	            key="cancel"
171	            component="button"
172	            isDisabled={!canEditResource}
173	            data-test-action="cancel-pipelineRun"
174	            tooltipProps={{
175	              content: t(
176	                'Interrupt any executing non finally tasks, then execute finally tasks',
177	              ),
178	            }}
179	            onClick={cancelAction}
180	          >
181	            {t('Cancel')}
182	          </DropdownItem>,
183	        ]
184	      : []),
185	    ...(!hidePLRStop
186	      ? [
187	          <DropdownItem
188	            key="stop"
189	            component="button"
190	            isDisabled={!canEditResource}
191	            data-test-action="stop-pipelineRun"
192	            tooltipProps={{
193	              content: t(
194	                'Let the running tasks complete, then execute finally tasks',
195	              ),
196	            }}
197	            onClick={stopAction}
198	          >
199	            {t('Stop')}
200	          </DropdownItem>,
201	        ]
202	      : []),
203	    <DropdownItem
204	      key="delete"
205	      component="button"
206	      onClick={launchDeleteModal}
207	      isDisabled={!canDeleteResource || isResourceLoadedFromTR(obj)}
208	      data-test-action="delete-pipelineRun"
209	    >
210	      {t('Delete PipelineRun')}
211	    </DropdownItem>,
212	  ];
213	
214	  return (
215	    <Dropdown
216	      onSelect={onSelect}
217	      onOpenChange={(isOpen: boolean) => setIsOpen(isOpen)}
218	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
219	        <MenuToggle
220	          ref={toggleRef}
221	          aria-label="kebab menu"
222	          variant="plain"
223	          onClick={onToggle}
224	          isExpanded={isOpen}
225	          id={KEBAB_BUTTON_ID}
226	          data-test={KEBAB_BUTTON_ID}
227	          icon={<EllipsisVIcon />}
228	        />
229	      )}
230	      isOpen={isOpen}
231	      isPlain={false}
232	      popperProps={{ placement: 'right-start' }}
233	    >
234	      <DropdownList>{dropdownItems}</DropdownList>
235	    </Dropdown>
236	  );
237	};
238	
239	export default PipelineRunsKebab;
